const widget = space.chat.transient?.widget || space.chat.transient?.data || space.chat.transient;
const source = typeof widget === "string" ? widget : (widget?.content ?? widget?.source ?? widget?.code ?? widget?.text ?? "");
if (!source) return "No widget source found in transient.";

const replacements = [
  // common instant-position updates
  {
    re: /([A-Za-z_$][\w$]*)\.x\s*=\s*([A-Za-z_$][\w$]*?)\.x\s*([+-])\s*([A-Za-z_$][\w$]*|[-+]?\d+(?:\.\d+)?)(\s*;?)/g,
    to: "$1._targetX = $2.x $3 $4$5"
  },
  {
    re: /([A-Za-z_$][\w$]*)\.y\s*=\s*([A-Za-z_$][\w$]*?)\.y\s*([+-])\s*([A-Za-z_$][\w$]*|[-+]?\d+(?:\.\d+)?)(\s*;?)/g,
    to: "$1._targetY = $2.y $3 $4$5"
  }
];

let updated = source;

// Add smoother interpolation helpers near top if absent
if (!/lerp\s*\(/.test(updated) && /class|function/.test(updated)) {
  updated = updated.replace(
    /(class\s+\w+\s*{)|(^\s*function\s+\w+\s*\()/m,
    `function lerp(a, b, t) { return a + (b - a) * t; }\nfunction smoothStep(t) { return t * t * (3 - 2 * t); }\n\n$1`
  );
}

// Upgrade direct square jumps to animated targets where possible
for (const { re, to } of replacements) updated = updated.replace(re, to);

// If there is a render/draw loop, inject interpolation for positions
if (/draw|render|update/.test(updated) && !/_animProgress|smoothStep/.test(updated)) {
  updated = updated.replace(
    /(function\s+(draw|render|update)\s*\([^)]*\)\s*{)/,
    `$1\n  const animT = Math.min(1, (performance.now() - (this?._moveStart ?? performance.now())) / Math.max(1, (this?._moveDuration ?? 120)));`
  );
}

// Make any move duration gentler if present
updated = updated
  .replace(/(_moveDuration\s*=\s*)\d+/g, "$1150")
  .replace(/(duration\s*:\s*)\d+/g, "$1150");

if (updated === source) {
  return "No safe automated edit pattern matched in the widget source.";
}

return await space.current.patchWidget("snake-game", {
  edits: [{ from: source, to: updated }]
})

